  ('aboriginal-6f0ba476-moex-00184', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '下列行為何者需課徵贈與稅？①保證人因履行保證責任，代主債務人清償債務並無償免除其債務', '["將公告現值500萬元之土地以400萬元賣給他人", "債務人依破產法破產，債權人因而有部分 債權無法收回", "兄弟之間買賣不動產，能提出已支付價款之確實證明", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00185', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依遺產及贈與稅法之規定，丙死亡前2年內所為之下列贈與，那一項不用併入遺產課稅？①贈與', '["贈與在死亡前已與其子離婚之媳婦之現金", "贈與堂兄弟土地", "贈與孫子 土地", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00186', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '有關地價稅稅率之敘述，下列何者錯誤？', '["公有土地稅率為千分之十", "都市計畫公共設施保留地未作任何使用並與使用中之土地隔離者，免徵地價稅", "持有土地超過20年者可減徵20%", "基本稅率為千分之十"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00187', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '下列有關主管稽徵機關得指定土地使用人負責代繳其使用部分之地價稅之情形，何者錯誤？', '["納稅義務人行蹤不明", "土地權屬不明", "因繼承取得之共有土地", "土地無人管理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00188', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '根據房屋稅條例規定，有關房屋稅稅率敘述，下列何者正確？', '["本人、配偶及未成年子女於全國僅持有一戶房屋，供自住且房屋現值在一定金額以下者，稅率 為1.2%", "土地設定地上權之使用權房屋並供該使用權人自住使用者，稅率為1%", "繼承取得之共有房屋，稅率最低不得少於1.5%，最高不得超過2.4%", "其他供住家用房屋，稅率最低不得少於1.5%，最高不得超過3.6%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00189', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依產業創新條例之規定，最近3年內無違反環境保護、勞工或食品安全衛生相關法律且情節重大 情事之公司投資於研究發展支出，有那些租稅優惠措施可以選擇，用以抵減應納營利事業所得', '["於支出金額15%限度內抵減當年度應納營利事業所得稅，且不得超過當年度應納稅額30%", "於支出金額 10%限度內，自當年度起 5 年內抵減各年度應納營利事業所得稅", "於支出金額 10%限度內，自當年度起3年內抵減各年度應納營利事業所得稅，且不得超過當年度應納稅額30%", "於支出金額15%限度內抵減當年度應納營利事業所得稅，且不得超過當年度應納稅額50%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
